CREATE TABLE users (
        id       INTEGER PRIMARY KEY AUTOINCREMENT,
        name     VARCHAR(255) NOT NULL,
        email    VARCHAR(255) NOT NULL UNIQUE,
        password VARCHAR(255) NOT NULL,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    , two_factor_secret VARCHAR(32) DEFAULT NULL, two_factor_enabled INTEGER DEFAULT 0);


CREATE TABLE sqlite_sequence(name,seq);


CREATE TABLE delivery_records (
        id             INTEGER PRIMARY KEY AUTOINCREMENT,
        invoice_no     VARCHAR(50),
        serial_no      VARCHAR(100),
        delivery_month VARCHAR(20),
        delivery_day   INTEGER,
        delivery_date  DATE,
        item_code      VARCHAR(50)  NOT NULL,
        item_name      VARCHAR(255),
        company_name   VARCHAR(255),
        quantity       INTEGER      NOT NULL DEFAULT 0,
        status         VARCHAR(50)  NOT NULL DEFAULT 'Delivered',
        notes          TEXT,
        created_at     TIMESTAMP    DEFAULT CURRENT_TIMESTAMP,
        updated_at     TIMESTAMP    DEFAULT CURRENT_TIMESTAMP
    , delivery_year INTEGER DEFAULT NULL, uom VARCHAR(50) DEFAULT NULL, groupings VARCHAR(50) DEFAULT NULL, sold_to_month VARCHAR(20) DEFAULT NULL, sold_to_day INTEGER DEFAULT NULL, dataset_name VARCHAR(50) DEFAULT NULL, `1` DECIMAL(12,2) DEFAULT NULL, `sr_x2v` VARCHAR(255) DEFAULT NULL, `replacement_surecell_oxygen_sensor` VARCHAR(255) DEFAULT NULL, `pc` VARCHAR(255) DEFAULT NULL, `02_13790264_032` VARCHAR(255) DEFAULT NULL, transferred_to VARCHAR(255) DEFAULT NULL, sold_to VARCHAR(255) NULL, box_code VARCHAR(50), model_no VARCHAR(100), description TEXT, order_customer VARCHAR(255), order_date DATE, unit_price DECIMAL(12,2) DEFAULT 0, total_amount DECIMAL(12,2) DEFAULT 0, po_number VARCHAR(100), po_status VARCHAR(50) DEFAULT 'No PO', `time_in` VARCHAR(50) DEFAULT NULL, `time_out` VARCHAR(50) DEFAULT NULL, `hours` DECIMAL(12,2) DEFAULT NULL);


CREATE TABLE user_settings (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL UNIQUE,
        settings TEXT,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    );


CREATE TABLE security_alerts (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    token VARCHAR(64) NOT NULL UNIQUE,
                    ip_address VARCHAR(45),
                    user_agent TEXT,
                    status VARCHAR(20) DEFAULT 'pending',
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    responded_at TIMESTAMP NULL
                );


CREATE TABLE login_attempts (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            email VARCHAR(255) NOT NULL,
            ip_address VARCHAR(45),
            user_agent TEXT,
            attempt_time TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        );


